    bitset(int n) : n(n) {

        data.assign((n + 63) / 64, 0);

    }

    void set(int i) {

        data[i / 64] |= (T(1) << (i % 64));

    }

    void reset(int i) {

        data[i / 64] &= ~(T(1) << (i % 64));

    }

    void flip(int i) {

        data[i / 64] ^= (T(1) << (i % 64));

    }

    bool test(int i) {

        return data[i / 64] & (T(1) << (i % 64));

    }

