        }

    }

    bool any() {

        rep(i, n) {

            if(test(i)) return true;

        }

        return false;

    }

    bool none() {

        rep(i, n) {

            if(test(i)) return false;

        }

        return true;

    }

    int count() {

        int res = 0;

        rep(i, n) {

            if(test(i)) res++;

        }

        return res;

    }

    int find_first() {

        rep(i, n) {

            if(test(i)) return i;

        }

        return -1;

    }

    int find_next(int i) {

        for(i++; i < n; i++) {

            if(test(i)) return i;

        }

        return -1;

    }

    int find_last() {

        rrep(i, n) {

            if(test(i)) return i;

        }

        return -1;

    }

    int find_prev(int i) {

        for(i--; i >= 0; i--) {

            if(test(i)) return i;

        }

        return -1;

    }

    friend ostream& operator<<(ostream& os, const bitset& bs) {

        rep(i, bs.n) {

            os << bs.test(i);

        }

        return os;

    }

};

